/**
 * ============================================================================
 * FIELD RESPONSIBILITY GUIDE
 * ============================================================================
 *
 * SYSTEM-MANAGED FIELDS (auto-generated, AI should NOT set):
 * - id: Auto-generated by system (inv:N, npc:N, loc:N, etc.)
 * - createdAt: Set when entity is created (Date.now())
 * - lastModified: Updated on any modification (Date.now())
 * - lastAccess: Updated when AI queries entity (turn number)
 * - isVisited: Set when player visits location
 * - discoveredAt: Set when location is first discovered
 *
 * AI-CONTROLLED FIELDS (AI decides value):
 * - visible.*: All visible layer content
 * - hidden.*: All hidden layer content (GM knowledge)
 * - unlocked: AI decides when hidden info is revealed (narrative judgment)
 * - known: Whether player knows this entity exists
 * - notes: NPC observations of player behavior
 * - highlight: Set true by AI when entity changes (cleared by UI after render)
 * - aliveEntities: AI marks entities needed for next turn
 *
 * MIXED FIELDS (AI sets initial, system may override):
 * - status: AI updates, but system may have constraints
 * - affinity: AI updates based on story, system validates range (0-100)
 * ============================================================================
 */

// Action Result type for handleAction return value
export interface StateChanges {
  // Detailed changes with names
  itemsAdded?: Array<{ name: string }>;
  itemsRemoved?: Array<{ name: string }>;
  npcsAdded?: Array<{ name: string }>;
  npcsRemoved?: Array<{ name: string }>;
  questsAdded?: Array<{ name: string }>;
  questsCompleted?: Array<{ name: string }>;
  locationsDiscovered?: Array<{ name: string }>;
  skillsGained?: Array<{ name: string }>;
  conditionsChanged?: Array<{ name: string }>;
}

export type ActionResult =
  | { success: true; stateChanges: StateChanges; legacyMessage: string }
  | { success: false; error: string };

// Context Priority System: How many recent/alive entities to include in context
export const RECENT_LIMITS = {
  inventory: 5,
  relationships: 4,
  locations: 3,
  quests: 3,
  knowledge: 4,
  timeline: 5,
} as const;

// Alive Entities: entities marked by AI as needed for next turn
export interface AliveEntities {
  inventory: string[]; // inv:N IDs
  relationships: string[]; // npc:N IDs
  locations: string[]; // loc:N IDs
  quests: string[]; // quest:N IDs
  knowledge: string[]; // know:N IDs
  timeline: string[]; // evt:N IDs
  // Character internal attributes (subset tracking)
  skills: string[]; // Character skill IDs relevant to next turn
  conditions: string[]; // Character condition IDs relevant to next turn
  hiddenTraits: string[]; // Character hidden trait IDs relevant to next turn
  causalChains: string[]; // CausalChain chainIds with pending consequences
}

export interface GameState {
  // Tree Structure: ID -> Segment
  nodes: Record<string, StorySegment>;
  activeNodeId: string | null; // The leaf node of the current path
  rootNodeId: string | null;

  inventory: InventoryItem[];
  relationships: Relationship[];
  quests: Quest[];
  character: CharacterStatus;
  knowledge: KnowledgeEntry[]; // Player's accumulated knowledge about the world
  factions: Faction[]; // Major power groups

  // Location System
  currentLocation: string;
  locations: Location[];

  // UI State (Persisted)
  uiState: UIState;

  // Meta
  outline: StoryOutline | null;
  summaries: StorySummary[]; // Array of summaries, where the last one is the most current
  lastSummarizedIndex: number; // Track how many nodes have been summarized to avoid re-summarizing

  isProcessing: boolean;
  isImageGenerating: boolean;
  generatingNodeId: string | null; // Track specifically which node is generating an image
  error: string | null;
  // Unified Atmosphere (controls visual theme, effects, and audio)
  atmosphere: string; // The current atmosphere (e.g. "forest", "horror", "city")
  theme: string; // Static game genre (e.g. "Cyberpunk", "Wuxia")
  time: string; // In-game time tracking

  // Stats & Logs
  totalTokens: number;
  logs: LogEntry[];

  // Cached Veo Script
  veoScript?: string;

  // Initial Prompt (for retry)
  initialPrompt?: string;

  // New World System Fields
  nextIds: {
    item: number;
    npc: number;
    location: number;
    knowledge: number;
    quest: number;
    faction: number;
    timeline: number;
    causalChain: number;
    skill: number;
    condition: number;
    hiddenTrait: number;
  };
  timeline: TimelineEvent[];
  causalChains: CausalChain[];

  // Context Priority System: entities AI marked as relevant for next turn
  // Cleared at start of each turn, populated by AI via finish_turn
  aliveEntities: AliveEntities;
  // RAG Queries: semantic search queries for next turn context
  // Populated by AI via finish_turn, used at start of next turn
  ragQueries?: string[];
  // Current turn number (incremented on each player action)
  turnNumber: number;

  // Developer Mode Flags
  godMode?: boolean; // God mode: bypass all restrictions and dangers
  unlockMode?: boolean; // Unlock mode: show all hidden info
}

// --- World System Interfaces ---

export interface VisibleInfo {
  description: string;
  appearance?: string;
  notes?: string;
  [key: string]: any;
}

export interface HiddenInfo {
  truth: string;
  realPersonality?: string;
  secrets?: string[];
  realMotives?: string;
  hiddenAttributes?: Record<string, any>;
  [key: string]: any;
}

export interface TimelineEvent {
  id: string;
  gameTime: string;
  category: "player_action" | "npc_action" | "world_event" | "consequence";
  visible: {
    description: string;
    causedBy?: string;
  };
  hidden: {
    trueDescription: string;
    trueCausedBy?: string;
    consequences?: string[];
  };
  involvedEntities?: string[];
  chainId?: string; // Link to a CausalChain
  lastAccess?: number; // Turn number when last accessed/queried by AI
  unlocked?: boolean; // True when true cause/consequences are revealed
  highlight?: boolean; // True when updated in current turn (for UI)
  known?: boolean; // True if the player is aware of this event
}

export interface CausalChain {
  chainId: string;
  rootCause: {
    eventId: string;
    description: string;
  };
  events: TimelineEvent[];
  status: "active" | "resolved" | "interrupted";
  /**
   * PENDING CONSEQUENCES (AI-DECIDED SYSTEM)
   *
   * The AI decides when consequences occur based on:
   * 1. Story context and player actions
   * 2. The 'readyAfterTurn' field (earliest possible trigger)
   * 3. Narrative appropriateness
   *
   * NOTE: 'probability' has been REMOVED. AI makes the decision.
   */
  pendingConsequences?: Array<{
    id: string; // Unique ID for tracking
    description: string; // What could happen
    readyAfterTurn: number; // Turn number AFTER which this consequence CAN trigger (not before)
    createdAtTurn: number; // Turn when this consequence was created
    conditions?: string[]; // Conditions that should be true for trigger (AI evaluates)
    triggered?: boolean; // True once consequence has been triggered
    triggeredAtTurn?: number; // Turn when triggered
    known?: boolean; // True if player witnessed/knows about this consequence
  }>;
}

export interface StorySummary {
  id: number;
  displayText: string; // Concise summary for UI display (visible layer only)
  visible: {
    narrative: string;
    majorEvents: string[];
    characterDevelopment: string;
    worldState: string;
  };
  hidden: {
    truthNarrative: string;
    hiddenPlots: string[];
    npcActions: string[];
    worldTruth: string;
    unrevealed: string[];
  };
  timeRange: {
    from: string;
    to: string;
  };
  nodeRange: {
    fromIndex: number;
    toIndex: number;
  };
}

export interface TokenUsage {
  promptTokens: number;
  completionTokens: number;
  totalTokens: number;
}

// Individual tool call record
export interface ToolCallRecord {
  name: string;
  input: Record<string, any>;
  output: any;
  timestamp: number;
}

export interface LogEntry {
  id: string;
  timestamp: number;
  provider: string;
  model: string;
  endpoint: string;
  // For agentic mode: array of tool calls in this turn
  toolCalls?: ToolCallRecord[];
  // Legacy fields for non-agentic mode
  request?: any;
  response?: any;
  usage?: TokenUsage;
}

export interface Faction {
  id: string;
  name: string;
  visible: {
    agenda: string; // Public agenda
    members?: { name: string; title?: string }[]; // Publicly known members
    influence?: string; // Perceived influence description
    relations?: Record<string, string>; // Public alliances/rivalries
  };
  hidden: {
    agenda: string; // Secret agenda
    members?: { name: string; title?: string }[]; // Secret members/leaders
    influence?: string; // True influence description
    relations?: Record<string, string>; // Secret alliances/rivalries
  };
  highlight?: boolean; // True when updated in current turn
  unlocked?: boolean; // True when secret agenda is revealed to player
}

export interface StoryOutline {
  title: string;
  initialTime: string;
  premise: string;
  mainGoal: {
    visible: string; // The apparent main motivation/task
    hidden: string; // The hidden event logic or true nature of the goal
  };
  quests: Quest[]; // Initial quests (replaces mainGoal/goals)
  worldSetting: {
    visible: string;
    hidden: string;
    history: string; // Ancient events that shape the present
  };
  factions: Omit<Faction, "id">[]; // Major power groups
  locations: Omit<Location, "id" | "isVisited" | "createdAt">[]; // Initial locations (Detailed structure)
  character: CharacterStatus; // Initial character state
  inventory?: InventoryItem[]; // Initial inventory
  relationships?: Relationship[]; // Initial relationships
  knowledge?: Omit<KnowledgeEntry, "id">[]; // Initial knowledge
  timeline?: TimelineEvent[]; // Initial timeline events (Backstory)
  // Unified Atmosphere for initial state
  initialAtmosphere: string; // Initial atmosphere (e.g. "forest", "horror", "city")
  // Unlocked flags - set by AI when player discovers hidden info
  worldSettingUnlocked?: boolean; // True when worldSetting.hidden is revealed
  mainGoalUnlocked?: boolean; // True when mainGoal.hidden is revealed
}

