export const CURRENT_SAVE_VERSION = 1;

export interface SaveVersionInfo {
  version: number;
  createdAt: number;
  migratedFrom?: number;
  migrationLog?: string[];
}

export interface VersionedGameState extends GameState {
  _saveVersion: SaveVersionInfo;
  _embeddingIndex?: EmbeddingIndex;
}

export interface ThemeData {
  name: string;
  narrativeStyle: string;
  backgroundTemplate: string;
  example: string;
  worldSetting: string;
}

export interface ModelInfo {
  id: string;
  name?: string;
  capabilities?: {
    image?: boolean;
    video?: boolean;
    audio?: boolean;
    text?: boolean;
    tools?: boolean;
    parallelTools?: boolean;
  };
}

export type FeedLayout = "scroll" | "stack";

export interface ImageGenerationContext {
  theme: string;
  worldSetting?: string; // Added worldSetting
  time?: string;
  location?: {
    name: string;
    environment: string;
    details: string;
  };
  character?: {
    name: string;
    race: string;
    profession: string;
    appearance: string;
    status: string;
  };
  activeNPCs?: {
    name: string;
    description: string;
    appearance: string;
    status: string;
  }[];
}
